from dataclasses import dataclass, field
from typing import List
import re

@dataclass
class ValidationResult:
    is_valid: bool
    sanitized_input: str
    violations: List[str]

class InputGuardrails:
    def __init__(self, max_length=4000, blocked_patterns=None, pii_patterns=None):
        self.max_length = max_length
        self.blocked_patterns = blocked_patterns or []
        self.pii_patterns = pii_patterns or {
            'email': r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
            'phone': r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b',
            'ssn': r'\b\d{3}-\d{2}-\d{4}\b',
            'credit_card': r'\b\d{4}[-\s]?\d{4}[-\s]?\d{4}[-\s]?\d{4}\b',
        }

    def validate(self, text: str) -> ValidationResult:
        violations = []
        sanitized = text
        if len(text) > self.max_length:
            violations.append(f"Input exceeds max length ({self.max_length})")
            sanitized = sanitized[:self.max_length]
        for pattern in self.blocked_patterns:
            if re.search(pattern, text, re.IGNORECASE):
                violations.append("Blocked pattern detected")
                sanitized = re.sub(pattern, '[BLOCKED]', sanitized, flags=re.IGNORECASE)
        for pii_type, pattern in self.pii_patterns.items():
            if re.search(pattern, text):
                violations.append(f"PII detected: {pii_type}")
                sanitized = re.sub(pattern, f'[{pii_type.upper()}_REDACTED]', sanitized)
        return ValidationResult(is_valid=len(violations) == 0,
                                sanitized_input=sanitized, violations=violations)

def check_input(text: str, detector, moderator, max_len: int = 4000) -> dict:
    """Run layered input checks, fast to slow."""
    if len(text) > max_len:
        return {"safe": False, "reason": "length_exceeded"}
    is_injection, _ = detector.detect(text)
    if is_injection:
        return {"safe": False, "reason": "prompt_injection"}
    mod = moderator.moderate(text)
    if mod["is_flagged"]:
        return {"safe": False, "reason": "moderation",
                "categories": mod["flagged_categories"]}
    return {"safe": True}

from openai import OpenAI
client = OpenAI()
def moderate(text: str, blocked_categories=None, threshold=0.5) -> dict: ALL_CATEGORIES = [ 'hate', 'hate/threatening', 'harassment', 'harassment/threatening', 'self-harm', 'self-harm/intent', 'sexual', 'sexual/minors', 'violence', 'violence/graphic', ] blocked = blocked_categories or ALL_CATEGORIES result = client.moderations.create(input=text).results[0] flagged = [] for cat in blocked: score = getattr(result.category_scores, cat.replace('/', '_').replace('-', '_')) if score > threshold: flagged.append({'category': cat, 'score': score}) return {'is_flagged': bool(flagged), 'flagged_categories': flagged}

